import * as THREE from 'three';

export class PlayerController {
    constructor(camera, domElement, groundHeight = 0) {
        this.camera = camera;
        this.domElement = domElement;
        this.groundHeight = groundHeight;
        
        // Movement state
        this.velocity = new THREE.Vector3();
        this.moveForward = false;
        this.moveBackward = false;
        this.moveLeft = false;
        this.moveRight = false;
        this.sprinting = false;
        this.jumping = false;
        this.isOnGround = false;

        // Parameters
        this.walkSpeed = 3.0;
        this.sprintSpeed = 5.0;
        this.jumpHeight = 0.3;
        this.gravity = -12;
        this.damping = 0.85;

        // Height
        this.playerHeight = 1.7;
        this.playerRadius = 0.3; // Collision radius
        this.camera.position.y = this.playerHeight + this.groundHeight;

        // Pointer lock
        this.isLocked = false;
        this.euler = new THREE.Euler(0, 0, 0, 'YXZ');
        this.pitchMin = -Math.PI / 2 + 0.1;
        this.pitchMax = Math.PI / 2 - 0.1;

        // ── 🔥 Collision meshes ──
        this.collisionMeshes = [];
        this.raycaster = new THREE.Raycaster();
        this.tempVec = new THREE.Vector3();
        this.tempDir = new THREE.Vector3();

        // ── Force mobile mode ──
        this.forceMobile = true;
        this.isMobile = true;
        this.isTouching = false;
        this.touchStartX = 0;
        this.touchStartY = 0;

        // Bind events
        this.onMouseMove = this.onMouseMove.bind(this);
        this.onKeyDown = this.onKeyDown.bind(this);
        this.onKeyUp = this.onKeyUp.bind(this);
        this.onLockChange = this.onLockChange.bind(this);
        this.onClick = this.onClick.bind(this);
        this.onTouchStart = this.onTouchStart.bind(this);
        this.onTouchMove = this.onTouchMove.bind(this);
        this.onTouchEnd = this.onTouchEnd.bind(this);
    }

    // ── 🔥 Set collision meshes ──
    setCollisionMeshes(meshes) {
        this.collisionMeshes = meshes;
        console.log(`🟢 Collision meshes set: ${meshes.length} objects`);
    }

    enable() {
        document.addEventListener('keydown', this.onKeyDown);
        document.addEventListener('keyup', this.onKeyUp);
        document.addEventListener('mousemove', this.onMouseMove);
        document.addEventListener('pointerlockchange', this.onLockChange);
        this.domElement.addEventListener('click', this.onClick);
        
        this.domElement.addEventListener('touchstart', this.onTouchStart, { passive: false });
        this.domElement.addEventListener('touchmove', this.onTouchMove, { passive: false });
        this.domElement.addEventListener('touchend', this.onTouchEnd, { passive: false });
        this.domElement.addEventListener('touchcancel', this.onTouchEnd, { passive: false });

        if (this.isMobile) {
            setTimeout(() => {
                this.domElement.requestPointerLock?.();
            }, 1000);
        }
    }

    disable() {
        document.removeEventListener('keydown', this.onKeyDown);
        document.removeEventListener('keyup', this.onKeyUp);
        document.removeEventListener('mousemove', this.onMouseMove);
        document.removeEventListener('pointerlockchange', this.onLockChange);
        this.domElement.removeEventListener('click', this.onClick);
        this.domElement.removeEventListener('touchstart', this.onTouchStart);
        this.domElement.removeEventListener('touchmove', this.onTouchMove);
        this.domElement.removeEventListener('touchend', this.onTouchEnd);
        this.domElement.removeEventListener('touchcancel', this.onTouchEnd);
        
        if (document.pointerLockElement) document.exitPointerLock();
    }

    // ── Desktop Controls ──
    onClick() {
        if (!this.isLocked) {
            this.domElement.requestPointerLock();
        }
    }

    onLockChange() {
        this.isLocked = document.pointerLockElement === this.domElement;
    }

    onMouseMove(e) {
        if (!this.isLocked) return;
        const movementX = e.movementX || 0;
        const movementY = e.movementY || 0;
        this.euler.setFromQuaternion(this.camera.quaternion);
        this.euler.y -= movementX * 0.002;
        this.euler.x -= movementY * 0.002;
        this.euler.x = Math.max(this.pitchMin, Math.min(this.pitchMax, this.euler.x));
        this.camera.quaternion.setFromEuler(this.euler);
    }

    // ── Mobile Controls ──
    onTouchStart(e) {
        const touch = e.touches[0];
        if (touch) {
            this.touchStartX = touch.clientX;
            this.touchStartY = touch.clientY;
            this.isTouching = true;
            
            if (!this.isLocked && this.domElement.requestPointerLock) {
                this.domElement.requestPointerLock();
            }
        }
    }

    onTouchMove(e) {
        e.preventDefault();
        if (!this.isTouching || !this.isLocked) return;
        
        const touch = e.touches[0];
        if (touch) {
            const deltaX = touch.clientX - this.touchStartX;
            const deltaY = touch.clientY - this.touchStartY;
            
            this.euler.setFromQuaternion(this.camera.quaternion);
            this.euler.y -= deltaX * 0.005;
            this.euler.x -= deltaY * 0.005;
            this.euler.x = Math.max(this.pitchMin, Math.min(this.pitchMax, this.euler.x));
            this.camera.quaternion.setFromEuler(this.euler);
            
            this.touchStartX = touch.clientX;
            this.touchStartY = touch.clientY;
        }
    }

    onTouchEnd() {
        this.isTouching = false;
    }

    // ── Keyboard Controls ──
    onKeyDown(e) {
        switch (e.code) {
            case 'KeyW': this.moveForward = true; break;
            case 'KeyS': this.moveBackward = true; break;
            case 'KeyA': this.moveLeft = true; break;
            case 'KeyD': this.moveRight = true; break;
            case 'ShiftLeft':
            case 'ShiftRight': this.sprinting = true; break;
            case 'Space':
                if (this.isOnGround) {
                    this.jumping = true;
                    this.isOnGround = false;
                }
                break;
        }
    }

    onKeyUp(e) {
        switch (e.code) {
            case 'KeyW': this.moveForward = false; break;
            case 'KeyS': this.moveBackward = false; break;
            case 'KeyA': this.moveLeft = false; break;
            case 'KeyD': this.moveRight = false; break;
            case 'ShiftLeft':
            case 'ShiftRight': this.sprinting = false; break;
        }
    }

    // ── 🔥 Check collision at a position ──
    checkCollision(position) {
        if (this.collisionMeshes.length === 0) return false;

        // Create a capsule-like collision check
        const radius = this.playerRadius;
        const halfHeight = this.playerHeight / 2;
        
        // Check multiple points around the player
        const checkPoints = [
            position.clone(),
            position.clone().add(new THREE.Vector3(radius, 0, 0)),
            position.clone().add(new THREE.Vector3(-radius, 0, 0)),
            position.clone().add(new THREE.Vector3(0, 0, radius)),
            position.clone().add(new THREE.Vector3(0, 0, -radius)),
            position.clone().add(new THREE.Vector3(radius * 0.7, 0, radius * 0.7)),
            position.clone().add(new THREE.Vector3(-radius * 0.7, 0, radius * 0.7)),
            position.clone().add(new THREE.Vector3(radius * 0.7, 0, -radius * 0.7)),
            position.clone().add(new THREE.Vector3(-radius * 0.7, 0, -radius * 0.7)),
        ];

        for (const point of checkPoints) {
            // Check from above and below
            const origin = point.clone().add(new THREE.Vector3(0, 2, 0));
            const direction = new THREE.Vector3(0, -1, 0);
            
            this.raycaster.set(origin, direction);
            const intersects = this.raycaster.intersectObjects(this.collisionMeshes, true);
            
            if (intersects.length > 0) {
                const hit = intersects[0];
                const distToGround = origin.y - hit.point.y;
                // If we hit something within the player height range
                if (distToGround < 2.5 && distToGround > 0.1) {
                    return true;
                }
            }
        }

        return false;
    }

    // ── 🔥 Simple check if position is inside any mesh ──
    isInsideMesh(position) {
        if (this.collisionMeshes.length === 0) return false;

        // Check if position is inside any mesh using raycasting
        const directions = [
            new THREE.Vector3(1, 0, 0),
            new THREE.Vector3(-1, 0, 0),
            new THREE.Vector3(0, 0, 1),
            new THREE.Vector3(0, 0, -1),
        ];

        for (const dir of directions) {
            this.raycaster.set(position, dir);
            const intersects = this.raycaster.intersectObjects(this.collisionMeshes, true);
            
            // If we hit something in all directions, we're inside
            if (intersects.length > 0) {
                const dist = intersects[0].distance;
                // Check opposite direction
                this.raycaster.set(position, dir.clone().negate());
                const intersects2 = this.raycaster.intersectObjects(this.collisionMeshes, true);
                if (intersects2.length > 0) {
                    const dist2 = intersects2[0].distance;
                    // If both distances are small, we're inside
                    if (dist < 2 && dist2 < 2) {
                        return true;
                    }
                }
            }
        }
        return false;
    }

    // ── Update ──
    update(delta = 1/60) {
        if (!this.isLocked && !this.forceMobile) return;

        const forward = new THREE.Vector3(0, 0, -1).applyQuaternion(this.camera.quaternion);
        forward.y = 0;
        forward.normalize();
        const right = new THREE.Vector3(1, 0, 0).applyQuaternion(this.camera.quaternion);
        right.y = 0;
        right.normalize();

        const speed = this.sprinting ? this.sprintSpeed : this.walkSpeed;

        const dir = new THREE.Vector3();
        if (this.moveForward) dir.add(forward);
        if (this.moveBackward) dir.sub(forward);
        if (this.moveLeft) dir.sub(right);
        if (this.moveRight) dir.add(right);
        if (dir.length() > 0) dir.normalize().multiplyScalar(speed);

        this.velocity.x += (dir.x - this.velocity.x) * (1 - this.damping);
        this.velocity.z += (dir.z - this.velocity.z) * (1 - this.damping);
        this.velocity.y += this.gravity * delta;

        if (this.jumping && this.isOnGround) {
            this.velocity.y = Math.sqrt(2 * this.jumpHeight * Math.abs(this.gravity));
            this.jumping = false;
        }

        // ── 🔥 Ground collision ──
        const newY = this.camera.position.y + this.velocity.y * delta;
        const groundY = this.groundHeight + this.playerHeight;
        
        if (newY <= groundY) {
            this.camera.position.y = groundY;
            this.velocity.y = 0;
            this.isOnGround = true;
        } else {
            this.camera.position.y = newY;
            this.isOnGround = false;
        }

        // ── 🔥 Horizontal collision with walls ──
        const newX = this.camera.position.x + this.velocity.x * delta;
        const newZ = this.camera.position.z + this.velocity.z * delta;

        // Check X movement
        const testPosX = new THREE.Vector3(newX, this.camera.position.y, this.camera.position.z);
        if (!this.checkCollision(testPosX) && !this.isInsideMesh(testPosX)) {
            this.camera.position.x = newX;
        } else {
            this.velocity.x = 0;
        }

        // Check Z movement
        const testPosZ = new THREE.Vector3(this.camera.position.x, this.camera.position.y, newZ);
        if (!this.checkCollision(testPosZ) && !this.isInsideMesh(testPosZ)) {
            this.camera.position.z = newZ;
        } else {
            this.velocity.z = 0;
        }
    }

    setGroundHeight(height) {
        this.groundHeight = height;
        this.camera.position.y = height + this.playerHeight;
    }
}