import * as THREE from 'three';

export class Engine {
  constructor(container) {
    this.container = container;

    // Scene
    this.scene = new THREE.Scene();
    this.scene.background = new THREE.Color(0x111118);

    // Camera
    const aspect = container.clientWidth / container.clientHeight;

    this.camera = new THREE.PerspectiveCamera(
      60,
      aspect,
      0.1,
      100
    );

    this.camera.position.set(0, 1.7, 5);

    // Renderer
    this.renderer = new THREE.WebGLRenderer({
      antialias: true,
      powerPreference: 'high-performance',
    });

    this.renderer.setPixelRatio(
      Math.min(window.devicePixelRatio, 2)
    );

    this.renderer.setSize(
      container.clientWidth,
      container.clientHeight
    );

    this.renderer.shadowMap.enabled = true;
    this.renderer.shadowMap.type = THREE.PCFSoftShadowMap;

    this.renderer.toneMapping = THREE.ACESFilmicToneMapping;
    this.renderer.toneMappingExposure = 1.2;

    this.renderer.outputColorSpace = THREE.SRGBColorSpace;


    // ── MOBILE OPTIMIZATION ──
    const isMobile =
      /Android|iPhone|iPad|iPod/i.test(navigator.userAgent);

    if (isMobile) {

      this.renderer.setPixelRatio(1);

      this.renderer.shadowMap.type =
        THREE.PCFSoftShadowMap;

      this.renderer.toneMappingExposure = 0.8;

      console.log(
        '📱 Mobile mode enabled - optimized for performance'
      );
    }


    container.appendChild(
      this.renderer.domElement
    );


    // Shader optimization state
    this.shadersPrecompiled = false;
  }



  // ── PRE-COMPILE SHADERS ──
  precompileShaders(scene, camera) {

    if (this.shadersPrecompiled) return;


    console.log(
      '🔄 Pre-compiling shaders...'
    );


    try {

      this.renderer.compile(
        scene,
        camera
      );


      this.shadersPrecompiled = true;


      console.log(
        '✅ Shaders pre-compiled successfully!'
      );


    } catch (error) {

      console.warn(
        '⚠️ Shader pre-compilation warning:',
        error
      );

    }

  }



  // ── GPU WARMUP ──
  warmupRenderer(scene, camera) {

    console.log(
      '🔥 Warming up renderer...'
    );


    try {

      this.renderer.render(
        scene,
        camera
      );


      console.log(
        '✅ Renderer warmed up!'
      );


    } catch(error) {

      console.warn(
        '⚠️ Renderer warmup warning:',
        error
      );

    }

  }



  // ── RESIZE HANDLER ──
  resize() {

    const width =
      this.container.clientWidth;

    const height =
      this.container.clientHeight;


    this.camera.aspect =
      width / height;


    this.camera.updateProjectionMatrix();


    this.renderer.setSize(
      width,
      height
    );

  }

}